"""Tests for atomic JSON file write utility."""

import json
from unittest.mock import patch

from claude_dashboard.file_utils import atomic_write_json


class TestAtomicWriteJson:
    def test_basic_write_and_read_roundtrip(self, tmp_path):
        """Write data and read it back — values match."""
        path = tmp_path / "out.json"
        data = {"key": "value", "count": 42, "nested": {"a": 1}}
        atomic_write_json(data=data, path=path)

        loaded = json.loads(path.read_text(encoding="utf-8"))
        assert loaded == data

    def test_creates_parent_directories(self, tmp_path):
        """Parent dirs are created automatically when they don't exist."""
        path = tmp_path / "a" / "b" / "c" / "deep.json"
        atomic_write_json(data={"ok": True}, path=path)

        assert path.exists()
        loaded = json.loads(path.read_text(encoding="utf-8"))
        assert loaded == {"ok": True}

    def test_write_failure_cleans_temp_and_preserves_original(self, tmp_path):
        """On write failure, temp file is removed and original file is untouched."""
        path = tmp_path / "original.json"
        path.write_text('{"original": true}\n', encoding="utf-8")

        with patch("builtins.open", side_effect=OSError("disk full")):
            try:
                atomic_write_json(data={"new": True}, path=path)
            except OSError:
                pass

        # Original content preserved
        loaded = json.loads(path.read_text(encoding="utf-8"))
        assert loaded == {"original": True}

        # No stray .tmp files left behind
        tmp_files = list(tmp_path.glob("*.tmp"))
        assert tmp_files == []

    def test_unicode_content(self, tmp_path):
        """Emoji and CJK characters survive roundtrip."""
        path = tmp_path / "unicode.json"
        data = {"emoji": "\U0001f604", "cjk": "\u4f60\u597d", "mixed": "hello \U0001f30d"}
        atomic_write_json(data=data, path=path)

        loaded = json.loads(path.read_text(encoding="utf-8"))
        assert loaded == data
        # ensure_ascii=False means raw characters in file, not escape sequences
        raw = path.read_text(encoding="utf-8")
        assert "\U0001f604" in raw
        assert "\u4f60\u597d" in raw

    def test_overwrites_existing_file(self, tmp_path):
        """Second write replaces first write completely."""
        path = tmp_path / "overwrite.json"
        atomic_write_json(data={"version": 1}, path=path)
        atomic_write_json(data={"version": 2}, path=path)

        loaded = json.loads(path.read_text(encoding="utf-8"))
        assert loaded == {"version": 2}

    def test_output_has_trailing_newline(self, tmp_path):
        """Written file ends with a newline character."""
        path = tmp_path / "newline.json"
        atomic_write_json(data={"a": 1}, path=path)

        raw = path.read_text(encoding="utf-8")
        assert raw.endswith("\n")
